const email = $json;
const system = 'You are an email triage engine for a company inbox. Classify the email into exactly one category: sales_inquiry, support, billing, cancellation, partnership, feedback, newsletter, notification, cold_outreach, spam, other.\n' +
  'Also assess urgency (high|normal|low), sentiment (positive|neutral|negative), whether a human-quality reply is needed (needs_reply), and write a one-line summary.\n' +
  'urgency=high when: outage or blocked work, an imminent deadline, refund dispute, legal threat, charge after cancellation, expiring trial with buying intent, or an angry repeat contact.\n' +
  'needs_reply=false for newsletter, notification, spam, and generic cold_outreach.\n' +
  'Respond with ONLY a JSON object, no markdown, no explanation: {"category":"...","urgency":"...","sentiment":"...","needs_reply":true,"summary":"...","confidence":0.0}';
const user = `From: ${email.from}\nSubject: ${email.subject}\n\n${(email.body || '').slice(0, 6000)}`;
return {
  json: {
    email,
    body: {
      model: $env.LLM_MODEL_CLASSIFY,
      temperature: 0,
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: user }
      ]
    }
  }
};

const email = $('Build Classify Request').item.json.email;
let raw = $json.choices?.[0]?.message?.content ?? '';
raw = raw.replace(/```json|```/g, '').trim();
let c = {};
try { c = JSON.parse(raw); } catch (e) { /* fall through to defaults */ }
const VALID = ['sales_inquiry','support','billing','cancellation','partnership','feedback','newsletter','notification','cold_outreach','spam','other'];
const classification = {
  category: VALID.includes(c.category) ? c.category : 'other',
  urgency: ['high','normal','low'].includes(c.urgency) ? c.urgency : 'normal',
  sentiment: ['positive','neutral','negative'].includes(c.sentiment) ? c.sentiment : 'neutral',
  needs_reply: typeof c.needs_reply === 'boolean' ? c.needs_reply : true,
  summary: typeof c.summary === 'string' ? c.summary : '',
  confidence: typeof c.confidence === 'number' ? c.confidence : null
};
return { json: { ...email, classification } };

const email = $json;
const query = `${email.subject}\n${(email.body || '').slice(0, 3000)}`;
return { json: { body: { model: $env.EMBEDDING_MODEL, input: query } } };

const item = $('Parse Classification').item.json;
const hits = ($json.result || [])
  .map(r => `[source: ${r.payload.source}]\n${r.payload.text}`)
  .join('\n\n---\n\n');
const system = 'You draft email replies for Flowdesk customer support. Rules:\n' +
  '- Use ONLY facts found in the KNOWLEDGE BASE CONTEXT. Never invent policies, prices, features, or dates.\n' +
  '- If the answer is not in the context, write [CHECK: what a human must verify] in that spot.\n' +
  '- Tone: friendly, direct, no corporate filler. Apologize at most once, then focus on the fix and a concrete next step.\n' +
  '- Keep it under 150 words. Sign off as "Flowdesk Support".\n' +
  '- Output the reply body only — no subject line, no preamble.';
const user = `KNOWLEDGE BASE CONTEXT:\n${hits || '(no relevant context found)'}\n\nINCOMING EMAIL:\nFrom: ${item.from}\nSubject: ${item.subject}\n\n${item.body}\n\nCLASSIFICATION: ${JSON.stringify(item.classification)}\n\nDraft the reply.`;
return {
  json: {
    body: {
      model: $env.LLM_MODEL_DRAFT,
      temperature: 0.3,
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: user }
      ]
    }
  }
};

const base = $('Parse Classification').item.json;
const kb = $('Search KB').item.json;
const sources = (kb?.result || []).map(r => r.payload.source);
const draft = $json.choices?.[0]?.message?.content?.trim() || '';
// If the LLM call failed (quota/rate limit/timeout), keep the triage result and
// flag the draft for retry instead of losing the whole run.
const err = $json.error?.message || $json.error || (draft ? null : 'no draft returned');
return { json: { ...base, draft_reply: draft,
  draft_status: draft ? 'ok' : 'failed',
  draft_error: draft ? null : String(err),
  kb_status: kb?.result ? 'ok' : 'unavailable',
  kb_sources: [...new Set(sources)] } };

const results = $input.all().map(i => i.json);
const by_category = {};
for (const r of results) {
  const c = r.classification?.category || 'other';
  by_category[c] = (by_category[c] || 0) + 1;
}
const urgent = results
  .filter(r => r.classification?.urgency === 'high')
  .map(r => ({ id: r.id, from: r.from, subject: r.subject, summary: r.classification.summary }));
return [{
  json: {
    run_at: new Date().toISOString(),
    total: results.length,
    drafted: results.filter(r => r.draft_reply).length,
    by_category,
    urgent,
    results
  }
}];

// Normalize a Gmail message into the same shape the mock workflow uses,
// so every downstream node is identical between the demo and live versions.
//
// The Gmail node (simple:false) hands back PARSED fields at the top level:
//   subject -> string
//   from/to -> mailparser objects: { value: [{ address, name }], text, html }
//   text/html -> body
// The raw Gmail API instead nests payload.headers as [{name,value}]. Handle
// both, so this works behind the polling trigger as well as the fetch node.
const m = $json;

const stripHtml = (s) => String(s)
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
  .replace(/\s+/g, ' ').trim();

// Raw-API fallback: payload.headers as an array of {name, value}
const raw = {};
if (Array.isArray(m.payload && m.payload.headers)) {
  for (const h of m.payload.headers) raw[String(h.name).toLowerCase()] = h.value;
}

// Pull a bare address out of whatever shape we were given.
function addressOf(v) {
  if (!v) return '';
  if (typeof v === 'string') {
    const hit = v.match(/<([^>]+)>/);
    return (hit ? hit[1] : v).trim();
  }
  const first = (v.value && v.value[0]) || null;
  if (first && first.address) return String(first.address).trim();
  const text = String(v.text || '');
  const hit = text.match(/<([^>]+)>/);
  return (hit ? hit[1] : text).trim();
}

function displayName(v) {
  if (!v) return '';
  if (typeof v === 'string') return v;
  const first = (v.value && v.value[0]) || null;
  if (first && first.name) return String(first.name);
  return addressOf(v);
}

let body = m.text || '';
if (!body && m.html) body = stripHtml(m.html);
if (!body) body = m.snippet || '';

const fromEmail = addressOf(m.from) || addressOf(raw.from);
const subject = m.subject || raw.subject || '(no subject)';
const receivedAt = m.date || raw.date || null;

return { json: {
  id: m.id,
  threadId: m.threadId,
  from: fromEmail || '(unknown sender)',
  from_name: displayName(m.from) || fromEmail,
  to: addressOf(m.to) || addressOf(raw.to),
  subject,
  body: String(body).slice(0, 8000),
  received_at: receivedAt,
} };

// Decide which labels this email earns, from the classification the LLM produced.
// Category label + a status label (drafted vs not) + urgency flag.
const email = $('Merge').item.json;
const byName = {};
for (const l of ($json.labels || [])) byName[l.name] = l.id;

const CATEGORY_LABEL = {
  sales_inquiry: 'AI/Sales',
  support:       'AI/Support',
  billing:       'AI/Billing',
  cancellation:  'AI/Cancellation',
  partnership:   'AI/Partnership',
  feedback:      'AI/Feedback',
  newsletter:    'AI/Newsletter',
  notification:  'AI/Notification',
  cold_outreach: 'AI/Cold Outreach',
  spam:          'AI/Spam',
  other:         'AI/Other',
};

const c = email.classification || {};
const hasDraft = !!(email.draft_reply && String(email.draft_reply).trim());

const names = [];
names.push(CATEGORY_LABEL[c.category] || 'AI/Other');
names.push(hasDraft ? 'AI/Needs Review' : 'AI/No Reply Needed');
if (c.urgency === 'high') names.push('AI/Urgent');

const addLabelIds = names.map(n => byName[n]).filter(Boolean);

// Drop the intake label so a re-run never processes the same mail twice.
const removeLabelIds = byName['ai-triage'] ? [byName['ai-triage']] : [];

return { json: { ...email, applied_labels: names, addLabelIds, removeLabelIds, has_draft: hasDraft } };

// The modify call returns the Gmail message resource, which would clobber our
// item. Put the enriched email back so the draft nodes still see their fields.
return { json: $('Resolve Labels').item.json };
